'use client';

import React, { useState } from 'react';
import {
  Box,
  Drawer,
  AppBar,
  Toolbar,
  Typography,
  Divider,
  List,
  ListItem,
  ListItemButton,
  ListItemIcon,
  ListItemText,
  Avatar,
  IconButton,
  Badge,
  InputBase,
  Paper,
  useTheme,
  alpha,
} from '@mui/material';
import {
  Menu as MenuIcon,
  Chat as ChatIcon,
  Assignment as AssignmentIcon,
  Security as SecurityIcon,
  Dashboard as DashboardIcon,
  Settings as SettingsIcon,
  Logout as LogoutIcon,
  Search as SearchIcon,
  Send as SendIcon,
  Notifications as NotificationsIcon,
  MoreVert as MoreVertIcon,
} from '@mui/icons-material';
import { useRouter } from 'next/navigation';

const drawerWidth = 280;
const chatPanelWidth = 380;

interface DashboardLayoutProps {
  children: React.ReactNode;
}

export default function DashboardLayout({ children }: DashboardLayoutProps) {
  const [mobileOpen, setMobileOpen] = useState(false);
  const [chatMessage, setChatMessage] = useState('');
  const router = useRouter();
  const theme = useTheme();

  const handleDrawerToggle = () => {
    setMobileOpen(!mobileOpen);
  };

  const menuItems = [
    { text: 'Dashboard', icon: <DashboardIcon />, path: '/dashboard' },
    { text: 'Compliance', icon: <AssignmentIcon />, path: '/compliance' },
    { text: 'Security', icon: <SecurityIcon />, path: '/security' },
  ];

  const chatUsers = [
    { name: 'Mark', active: true, avatar: 'M', lastMessage: 'Hey, can you check...' },
    { name: 'Sandeep', active: false, avatar: 'S', lastMessage: 'Compliance report ready' },
    { name: 'Jon', active: true, avatar: 'J', lastMessage: 'Thanks for the update' },
  ];

  const agents = [
    { name: 'Compliance Agent', icon: '🤖', color: '#3b82f6', status: 'online' },
    { name: 'Approvals Agent', icon: '✅', color: '#10b981', status: 'online' },
    { name: 'Tower Agent', icon: '🏗️', color: '#f59e0b', status: 'online' },
  ];

  const drawer = (
    <Box sx={{ 
      overflow: 'auto', 
      height: '100%', 
      display: 'flex', 
      flexDirection: 'column',
      bgcolor: 'sidebar.background',
      color: 'sidebar.text',
    }}>
      <Toolbar sx={{ justifyContent: 'center', py: 3 }}>
        <Typography variant="h6" sx={{ color: 'white', fontWeight: 700, letterSpacing: '0.5px' }}>
          Crystal Clean AI
        </Typography>
      </Toolbar>
      <Divider sx={{ borderColor: 'sidebar.border' }} />
      
      {/* Main Menu */}
      <List sx={{ px: 2, py: 2 }}>
        {menuItems.map((item) => (
          <ListItem key={item.text} disablePadding sx={{ mb: 1 }}>
            <ListItemButton 
              onClick={() => router.push(item.path)}
              sx={{
                borderRadius: '8px',
                color: 'sidebar.text',
                '&:hover': {
                  bgcolor: 'sidebar.hover',
                },
              }}
            >
              <ListItemIcon sx={{ color: 'sidebar.text', minWidth: 40 }}>
                {item.icon}
              </ListItemIcon>
              <ListItemText primary={item.text} />
            </ListItemButton>
          </ListItem>
        ))}
      </List>
      
      <Divider sx={{ borderColor: 'sidebar.border' }} />
      
      {/* All Chats Section */}
      <Box sx={{ px: 3, py: 2 }}>
        <Typography variant="overline" sx={{ color: alpha('#fff', 0.5), fontWeight: 600 }}>
          ALL CHATS
        </Typography>
      </Box>
      
      <List sx={{ px: 2 }}>
        {chatUsers.map((user) => (
          <ListItem key={user.name} disablePadding sx={{ mb: 1 }}>
            <ListItemButton
              sx={{
                borderRadius: '8px',
                color: 'sidebar.text',
                '&:hover': {
                  bgcolor: 'sidebar.hover',
                },
              }}
            >
              <ListItemIcon sx={{ minWidth: 40 }}>
                <Badge
                  color="success"
                  variant="dot"
                  invisible={!user.active}
                  anchorOrigin={{
                    vertical: 'bottom',
                    horizontal: 'right',
                  }}
                >
                  <Avatar sx={{ width: 32, height: 32, bgcolor: user.active ? theme.palette.primary.main : '#6b7280' }}>
                    {user.avatar}
                  </Avatar>
                </Badge>
              </ListItemIcon>
              <ListItemText 
                primary={user.name} 
                secondary={user.lastMessage}
                secondaryTypographyProps={{
                  sx: { color: alpha('#fff', 0.5), fontSize: '0.75rem' }
                }}
              />
            </ListItemButton>
          </ListItem>
        ))}
        <ListItem disablePadding>
          <ListItemButton
            sx={{
              borderRadius: '8px',
              color: 'sidebar.text',
              '&:hover': {
                bgcolor: 'sidebar.hover',
              },
            }}
          >
            <ListItemIcon sx={{ color: 'sidebar.text', minWidth: 40 }}>
              <ChatIcon />
            </ListItemIcon>
            <ListItemText primary="Chat" />
          </ListItemButton>
        </ListItem>
      </List>
      
      <Box sx={{ flexGrow: 1 }} />
      
      <Divider sx={{ borderColor: 'sidebar.border' }} />
      
      {/* Bottom Menu */}
      <List sx={{ px: 2, py: 2 }}>
        <ListItem disablePadding sx={{ mb: 1 }}>
          <ListItemButton
            sx={{
              borderRadius: '8px',
              color: 'sidebar.text',
              '&:hover': {
                bgcolor: 'sidebar.hover',
              },
            }}
          >
            <ListItemIcon sx={{ color: 'sidebar.text', minWidth: 40 }}>
              <SettingsIcon />
            </ListItemIcon>
            <ListItemText primary="Settings" />
          </ListItemButton>
        </ListItem>
        <ListItem disablePadding>
          <ListItemButton
            onClick={() => router.push('/')}
            sx={{
              borderRadius: '8px',
              color: 'sidebar.text',
              '&:hover': {
                bgcolor: 'sidebar.hover',
              },
            }}
          >
            <ListItemIcon sx={{ color: 'sidebar.text', minWidth: 40 }}>
              <LogoutIcon />
            </ListItemIcon>
            <ListItemText primary="Logout" />
          </ListItemButton>
        </ListItem>
      </List>
    </Box>
  );

  return (
    <Box sx={{ display: 'flex', height: '100vh', overflow: 'hidden' }}>
      {/* Dark Sidebar */}
      <Box
        component="nav"
        sx={{ width: { sm: drawerWidth }, flexShrink: { sm: 0 } }}
      >
        <Drawer
          variant="permanent"
          sx={{
            display: { xs: 'none', sm: 'block' },
            '& .MuiDrawer-paper': { 
              boxSizing: 'border-box', 
              width: drawerWidth,
              bgcolor: 'sidebar.background',
              border: 'none',
            },
          }}
          open
        >
          {drawer}
        </Drawer>
      </Box>

      {/* Main Content Area */}
      <Box sx={{ 
        display: 'flex', 
        flex: 1, 
        overflow: 'hidden',
        bgcolor: 'background.default',
      }}>
        {/* Dashboard Content */}
        <Box sx={{ 
          flex: 1, 
          overflow: 'auto',
          p: 3,
        }}>
          {/* Header */}
          <Paper sx={{ p: 2, mb: 3, display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
            <Typography variant="h6">Dashboard</Typography>
            <Box sx={{ display: 'flex', gap: 1 }}>
              <IconButton size="small">
                <Badge badgeContent={3} color="error">
                  <NotificationsIcon />
                </Badge>
              </IconButton>
              <Avatar sx={{ width: 32, height: 32, bgcolor: theme.palette.primary.main }}>U</Avatar>
            </Box>
          </Paper>
          
          {children}
        </Box>

        {/* Right Chat Panel */}
        <Paper sx={{
          width: chatPanelWidth,
          borderLeft: `1px solid ${theme.palette.divider}`,
          display: 'flex',
          flexDirection: 'column',
          height: '100vh',
          borderRadius: 0,
        }}>
          {/* Chat Header */}
          <Box sx={{ p: 2, borderBottom: `1px solid ${theme.palette.divider}` }}>
            <Typography variant="h6" gutterBottom>AI Assistants</Typography>
            <Box sx={{ display: 'flex', gap: 1, mt: 1 }}>
              {agents.map((agent) => (
                <Chip
                  key={agent.name}
                  label={agent.name}
                  size="small"
                  icon={<span>{agent.icon}</span>}
                  sx={{
                    bgcolor: alpha(agent.color, 0.1),
                    color: agent.color,
                    border: `1px solid ${alpha(agent.color, 0.2)}`,
                  }}
                />
              ))}
            </Box>
          </Box>

          {/* Chat Messages */}
          <Box sx={{ flex: 1, overflow: 'auto', p: 2 }}>
            <ChatMessage 
              agent="Compliance Agent"
              message="I can help you run compliance checks. Try @ComplianceAgent run compliance report for Site A"
              timestamp="10:30 AM"
              avatar="🤖"
              color="#3b82f6"
            />
            <ChatMessage 
              agent="Approvals Agent"
              message="Ready to review and approve reports. @ApprovalsAgent approve report v1"
              timestamp="10:31 AM"
              avatar="✅"
              color="#10b981"
              isUser={false}
            />
          </Box>

          {/* Chat Input */}
          <Box sx={{ p: 2, borderTop: `1px solid ${theme.palette.divider}` }}>
            <Paper
              component="form"
              sx={{
                p: '2px 4px',
                display: 'flex',
                alignItems: 'center',
                border: `1px solid ${theme.palette.divider}`,
                boxShadow: 'none',
              }}
            >
              <InputBase
                sx={{ ml: 1, flex: 1 }}
                placeholder="Type a message... (Use @ to mention agents)"
                value={chatMessage}
                onChange={(e) => setChatMessage(e.target.value)}
              />
              <IconButton type="button" sx={{ p: '10px' }} color="primary">
                <SendIcon />
              </IconButton>
            </Paper>
            <Typography variant="caption" color="text.secondary" sx={{ mt: 1, display: 'block' }}>
              Try: @ComplianceAgent run compliance report for Site A
            </Typography>
          </Box>
        </Paper>
      </Box>
    </Box>
  );
}

// Chat Message Component
function ChatMessage({ agent, message, timestamp, avatar, color, isUser = false }: any) {
  return (
    <Box sx={{ mb: 2, display: 'flex', gap: 1 }}>
      <Avatar sx={{ bgcolor: color, width: 32, height: 32 }}>
        {avatar}
      </Avatar>
      <Box sx={{ flex: 1 }}>
        <Box sx={{ display: 'flex', justifyContent: 'space-between', mb: 0.5 }}>
          <Typography variant="subtitle2">{agent}</Typography>
          <Typography variant="caption" color="text.secondary">{timestamp}</Typography>
        </Box>
        <Paper sx={{ p: 1.5, bgcolor: isUser ? alpha(color, 0.1) : 'background.paper' }}>
          <Typography variant="body2">{message}</Typography>
        </Paper>
      </Box>
    </Box>
  );
}

// Import Chip
import Chip from '@mui/material/Chip';